85	func UsageCostAttribution(rawUsage string) (*agent.CostAttribution, bool) {
86		if strings.TrimSpace(rawUsage) == "" {
87			return nil, false
88		}
89	
90		// OpenRouter extends the OpenAI-compatible usage object with a billed USD
91		// cost field at usage.cost. Preserve it when present instead of guessing from
92		// a local pricing table.
93		var usage struct {
94			Cost *float64 `json:"cost"`
95		}
96		if err := json.Unmarshal([]byte(rawUsage), &usage); err != nil || usage.Cost == nil || *usage.Cost < 0 {
97			return nil, false
98		}
99	
100		return &agent.CostAttribution{
101			Source:     agent.CostSourceGatewayReported,
102			Currency:   "USD",
103			Amount:     usage.Cost,
104			PricingRef: "openrouter/usage.cost",
105			Raw:        json.RawMessage(rawUsage),
106		}, true
107	}
