109	func LookupModelLimits(ctx context.Context, baseURL, apiKey string, headers map[string]string, model string) limits.ModelLimits {
110		var list struct {
111			Data []struct {
112				ID            string `json:"id"`
113				ContextLength int    `json:"context_length"`
114				TopProvider   struct {
115					MaxCompletionTokens int `json:"max_completion_tokens"`
116				} `json:"top_provider"`
117			} `json:"data"`
118		}
119		endpoint := strings.TrimRight(baseURL, "/") + "/models"
120		if err := getAndDecode(ctx, 10*time.Second, endpoint, apiKey, headers, &list); err != nil {
121			return limits.ModelLimits{}
122		}
123	
124		normalizeID := func(s string) string {
125			return strings.ToLower(strings.ReplaceAll(s, "-", "."))
126		}
127		normModel := normalizeID(model)
128		for _, m := range list.Data {
129			if strings.EqualFold(m.ID, model) || normalizeID(m.ID) == normModel {
130				return limits.ModelLimits{
131					ContextLength:       m.ContextLength,
132					MaxCompletionTokens: m.TopProvider.MaxCompletionTokens,
133				}
134			}
135		}
136		return limits.ModelLimits{}
137	}
138	
139	func getAndDecode(ctx context.Context, timeout time.Duration, endpoint, apiKey string, headers map[string]string, out any) error {
140		reqCtx, cancel := context.WithTimeout(ctx, timeout)
141		defer cancel()
142	
143		req, err := http.NewRequestWithContext(reqCtx, http.MethodGet, endpoint, nil)
144		if err != nil {
145			return err
146		}
147		req.Header.Set("Accept", "application/json")
148		if apiKey != "" {
149			req.Header.Set("Authorization", "Bearer "+apiKey)
150		}
151		for k, v := range headers {
152			req.Header.Set(k, v)
153		}
154	
155		resp, err := http.DefaultClient.Do(req)
156		if err != nil {
157			return err
158		}
159		defer resp.Body.Close() //nolint:errcheck
160	
161		if resp.StatusCode != http.StatusOK {
162			body, _ := io.ReadAll(io.LimitReader(resp.Body, 256))
163			return fmt.Errorf("HTTP %d: %s", resp.StatusCode, strings.TrimSpace(string(body)))
164		}
165		return json.NewDecoder(resp.Body).Decode(out)
166	}
