13	const (
14		// defaultHealthProbeInterval is the interval between background aliveness
15		// probes when ServiceOptions.HealthProbeInterval is zero.
16		defaultHealthProbeInterval = 60 * time.Second
17		// defaultHealthSignalTTL is the maximum age of a probe result used to
18		// populate routing.Inputs.ProbeUnreachable when HealthSignalTTL is zero.
19		defaultHealthSignalTTL = 10 * time.Minute
20		// routeTimeProbeTimeout bounds one synchronous route-time aliveness probe
21		// before the provider is treated as unreachable for that route decision.
22		routeTimeProbeTimeout = 2 * time.Second
23		// startupProbeTotalTimeout bounds the total wall-clock time spent on
24		// startup aliveness probes, regardless of provider count.
25		startupProbeTotalTimeout = 5 * time.Second
26	)
27	
28	// ProviderAlivenessProber reports whether a provider endpoint is reachable.
29	// Returns true if reachable, false if not. The prober must respect ctx for
30	// cancellation.
31	type ProviderAlivenessProber func(ctx context.Context, provider, baseURL string) bool
32	
33	// alivenessEndpoint describes one provider endpoint to probe.
34	type alivenessEndpoint struct {
35		provider string
36		endpoint string
37		baseURL  string
38	}
39	
40	func (s *service) healthProbeInterval() time.Duration {
41		if s.opts.HealthProbeInterval > 0 {
42			return s.opts.HealthProbeInterval
43		}
44		return defaultHealthProbeInterval
45	}
46	
47	func (s *service) healthSignalTTL() time.Duration {
48		if s.opts.HealthSignalTTL > 0 {
49			return s.opts.HealthSignalTTL
50		}
51		return defaultHealthSignalTTL
52	}
53	
54	// alivenessEndpoints enumerates the non-cloud provider endpoints that
55	// should be probed. Only providers whose billing type indicates fixed/local
56	// billing are included; cloud subscription providers are excluded.
57	func (s *service) alivenessEndpoints() []alivenessEndpoint {
58		if s.opts.ServiceConfig == nil {
59			return nil
60		}
61		var endpoints []alivenessEndpoint
62		seen := make(map[string]struct{})
63		for _, name := range s.opts.ServiceConfig.ProviderNames() {
64			entry, ok := s.opts.ServiceConfig.Provider(name)
65			if !ok || entry.ConfigError != "" {
66				continue
67			}
68			if !providerTypeUsesFixedBilling(entry.Type) {
69				continue
70			}
71			for _, endpoint := range modelDiscoveryEndpoints(entry) {
72				if endpoint.BaseURL == "" {
73					continue
74				}
75				key := name + "|" + endpoint.Name + "|" + endpoint.BaseURL
76				if _, dup := seen[key]; !dup {
77					seen[key] = struct{}{}
78					endpoints = append(endpoints, alivenessEndpoint{
79						provider: name,
80						endpoint: endpoint.Name,
81						baseURL:  endpoint.BaseURL,
82					})
83				}
84			}
85		}
86		return endpoints
87	}
88	
89	// startupAlivenessProbe probes all configured non-cloud providers synchronously.
90	// It is reserved for explicit diagnostics/tests; New starts only the background
91	// probe loop so service construction cannot block on dead local endpoints.
92	func (s *service) startupAlivenessProbe(ctx context.Context) {
93		if s.providerProbe == nil {
94			return
95		}
96		endpoints := s.alivenessEndpoints()
97		if len(endpoints) == 0 {
98			return
99		}
100		prober := s.opts.AlivenessProber
101		if prober == nil {
102			prober = tcpAlivenessProber
103		}
104		runStartupAlivenessProbes(ctx, endpoints, s.providerProbe, prober, startupProbeTotalTimeout)
105		s.persistProbeStore()
106	}
107	
108	// runStartupAlivenessProbes probes each endpoint sequentially within totalTimeout.
109	// It is exported as a standalone function for direct testing.
110	func runStartupAlivenessProbes(
111		ctx context.Context,
112		endpoints []alivenessEndpoint,
113		store *routehealth.ProbeStore,
114		prober ProviderAlivenessProber,
115		totalTimeout time.Duration,
116	) {
117		if len(endpoints) == 0 || store == nil || prober == nil {
118			return
119		}
120		probeCtx := ctx
121		if totalTimeout > 0 {
122			var cancel context.CancelFunc
123			probeCtx, cancel = context.WithTimeout(ctx, totalTimeout)
124			defer cancel()
125		}
126		now := time.Now().UTC()
127		for _, ep := range endpoints {
128			if probeCtx.Err() != nil {
129				break
130			}
131			success := prober(probeCtx, ep.provider, ep.baseURL)
132			if probeCtx.Err() != nil {
133				success = false
134			}
135			store.RecordProbe(ep.provider, ep.endpoint, success, now)
136		}
137	}
138	
139	func (s *service) persistProbeStore() {
140		s.persistRouteHealthSnapshot()
141	}
142	
143	// requestLocalHealthRefreshForRouting starts at most one asynchronous refresh
144	// for stale or missing local provider aliveness evidence. Route hot paths use
145	// cached probe evidence only; this method must not wait for provider IO.
146	func (s *service) requestLocalHealthRefreshForRouting(_ context.Context) {
147		if s == nil || s.providerProbe == nil {
148			return
149		}
150		endpoints := s.routeTimeAlivenessEndpoints(time.Now().UTC())
151		if len(endpoints) == 0 {
152			return
153		}
154		if !s.providerProbeRefreshInFlight.CompareAndSwap(false, true) {
155			return
156		}
157		prober := s.opts.AlivenessProber
158		if prober == nil {
159			prober = tcpAlivenessProber
160		}
161		refreshCtx := context.Background()
162		go func() {
163			defer s.providerProbeRefreshInFlight.Store(false)
164			runRouteTimeAlivenessProbes(refreshCtx, endpoints, s.providerProbe, prober, routeTimeProbeTimeout)
165			s.persistProbeStore()
166		}()
167	}
