169	func (s *service) probeUnknownProviders(now time.Time) map[string]time.Time {
170		if s == nil || s.providerProbe == nil {
171			return nil
172		}
173		endpoints := s.alivenessEndpoints()
174		if len(endpoints) == 0 {
175			return nil
176		}
177		if now.IsZero() {
178			now = time.Now().UTC()
179		}
180		ttl := s.healthSignalTTL()
181		out := make(map[string]time.Time)
182		for _, ep := range endpoints {
183			record, ok := s.lastProbeForAlivenessEndpoint(ep)
184			if !ok {
185				for _, key := range alivenessRouteKeys(ep) {
186					out[key] = time.Time{}
187				}
188				continue
189			}
190			if ttl > 0 && now.Sub(record.LastProbeAt) > ttl {
191				for _, key := range alivenessRouteKeys(ep) {
192					out[key] = record.LastProbeAt
193				}
194			}
195		}
196		if len(out) == 0 {
197			return nil
198		}
199		return out
200	}
201	
202	func (s *service) routeTimeAlivenessEndpoints(now time.Time) []alivenessEndpoint {
203		if s == nil || s.providerProbe == nil {
204			return nil
205		}
206		endpoints := s.alivenessEndpoints()
207		if len(endpoints) == 0 {
208			return nil
209		}
210		interval := s.healthProbeInterval()
211		out := make([]alivenessEndpoint, 0, len(endpoints))
212		for _, ep := range endpoints {
213			if s.probeNeededForAlivenessEndpoint(ep, now, interval) {
214				out = append(out, ep)
215			}
216		}
217		return out
218	}
219	
220	func (s *service) probeNeededForAlivenessEndpoint(ep alivenessEndpoint, now time.Time, interval time.Duration) bool {
221		if s == nil || s.providerProbe == nil {
222			return false
223		}
224		if !s.providerProbe.ProbeNeeded(ep.provider, ep.endpoint, now, interval) {
225			return false
226		}
227		if ep.endpoint == "" {
228			return true
229		}
230		if r, ok := s.providerProbe.LastProbe(ep.provider, ""); ok {
231			return now.Sub(r.LastProbeAt) >= interval
232		}
233		return true
234	}
235	
236	func (s *service) probeUnreachableProviders(now time.Time) map[string]time.Time {
237		if s == nil || s.providerProbe == nil {
238			return nil
239		}
240		endpoints := s.alivenessEndpoints()
241		if len(endpoints) == 0 {
242			return nil
243		}
244		if now.IsZero() {
245			now = time.Now().UTC()
246		}
247		ttl := s.healthSignalTTL()
248		out := make(map[string]time.Time)
249		for _, ep := range endpoints {
250			record, ok := s.lastProbeForAlivenessEndpoint(ep)
251			if !ok || record.LastProbeSuccess {
252				continue
253			}
254			if ttl > 0 && now.Sub(record.LastProbeAt) > ttl {
255				continue
256			}
257			for _, key := range alivenessRouteKeys(ep) {
258				if existing, ok := out[key]; !ok || record.LastProbeAt.After(existing) {
259					out[key] = record.LastProbeAt
260				}
261			}
262		}
263		if len(out) == 0 {
264			return nil
265		}
266		return out
267	}
268	
269	func (s *service) lastProbeForAlivenessEndpoint(ep alivenessEndpoint) (routehealth.ProbeRecord, bool) {
270		if s == nil || s.providerProbe == nil {
271			return routehealth.ProbeRecord{}, false
272		}
273		if r, ok := s.providerProbe.LastProbe(ep.provider, ep.endpoint); ok {
274			return r, true
275		}
276		if ep.endpoint != "" {
277			return s.providerProbe.LastProbe(ep.provider, "")
278		}
279		return routehealth.ProbeRecord{}, false
280	}
281	
282	func alivenessRouteKeys(ep alivenessEndpoint) []string {
283		provider := strings.TrimSpace(ep.provider)
284		if provider == "" {
285			return nil
286		}
287		endpoint := strings.TrimSpace(ep.endpoint)
288		if endpoint == "" {
289			return []string{provider}
290		}
291		ref := endpointProviderRef(provider, endpoint)
292		if ref == provider {
293			return []string{provider}
294		}
295		return []string{provider, ref}
296	}
297	
298	func runRouteTimeAlivenessProbes(
299		ctx context.Context,
300		endpoints []alivenessEndpoint,
301		store *routehealth.ProbeStore,
302		prober ProviderAlivenessProber,
303		perProbeTimeout time.Duration,
304	) {
305		if len(endpoints) == 0 || store == nil || prober == nil {
306			return
307		}
308		if ctx == nil {
309			ctx = context.Background()
310		}
311		if perProbeTimeout <= 0 {
312			perProbeTimeout = routeTimeProbeTimeout
313		}
314		for i, ep := range endpoints {
315			if ctx.Err() != nil {
316				recordRouteTimeProbeFailures(store, endpoints[i:], time.Now().UTC())
317				return
318			}
319			probeAt := time.Now().UTC()
320			probeCtx, cancel := context.WithTimeout(ctx, perProbeTimeout)
321			success := prober(probeCtx, ep.provider, ep.baseURL)
322			if probeCtx.Err() != nil {
323				success = false
324			}
325			cancel()
326			store.RecordProbe(ep.provider, ep.endpoint, success, probeAt)
327			if ctx.Err() != nil {
328				recordRouteTimeProbeFailures(store, endpoints[i+1:], probeAt)
329				return
330			}
331		}
332	}
333	
334	func recordRouteTimeProbeFailures(store *routehealth.ProbeStore, endpoints []alivenessEndpoint, probeAt time.Time) {
335		if store == nil || len(endpoints) == 0 {
336			return
337		}
338		for _, ep := range endpoints {
339			store.RecordProbe(ep.provider, ep.endpoint, false, probeAt)
340		}
341	}
342	
343	// startAlivenessProbeLoop spawns the goroutine that periodically re-probes
344	// configured non-cloud providers. The goroutine is tied to QuotaRefreshContext
345	// (or context.Background()) so server callers can cancel it on shutdown.
346	func (s *service) startAlivenessProbeLoop() {
347		if s.providerProbe == nil {
348			return
349		}
350		endpoints := s.alivenessEndpoints()
351		if len(endpoints) == 0 {
352			return
353		}
354		ctx := s.opts.QuotaRefreshContext
355		if ctx == nil {
356			ctx = context.Background()
357		}
358		prober := s.opts.AlivenessProber
359		if prober == nil {
360			prober = tcpAlivenessProber
361		}
362		store := s.providerProbe
363		interval := s.healthProbeInterval()
364		persistPath := s.opts.PersistRouteHealth
365		go runAlivenessProbeLoop(ctx, endpoints, store, prober, interval, nil, nil, persistPath)
366	}
367	
368	// runAlivenessProbeLoop periodically re-probes each endpoint whose last probe
369	// is older than interval. now and sleep are seams for deterministic tests;
370	// pass nil for production defaults.
371	func runAlivenessProbeLoop(
372		ctx context.Context,
373		endpoints []alivenessEndpoint,
374		store *routehealth.ProbeStore,
375		prober ProviderAlivenessProber,
376		interval time.Duration,
377		now func() time.Time,
378		sleep func(ctx context.Context, d time.Duration) bool,
379		persistPath string,
380	) {
381		if now == nil {
382			now = time.Now
383		}
384		if sleep == nil {
385			sleep = alivenessLoopSleep
386		}
387		if interval <= 0 {
388			interval = defaultHealthProbeInterval
389		}
390		for {
391			t := now().UTC()
392			for _, ep := range endpoints {
393				if ctx.Err() != nil {
394					return
395				}
396				if !store.ProbeNeeded(ep.provider, ep.endpoint, t, interval) {
397					continue
398				}
399				probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
400				success := prober(probeCtx, ep.provider, ep.baseURL)
401				cancel()
402				store.RecordProbe(ep.provider, ep.endpoint, success, t)
403			}
404			if persistPath != "" {
405				_ = store.Save(persistPath)
406			}
407			if !sleep(ctx, interval) {
408				return
409			}
410		}
411	}
412	
413	func alivenessLoopSleep(ctx context.Context, d time.Duration) bool {
414		if d <= 0 {
415			return ctx.Err() == nil
416		}
417		timer := time.NewTimer(d)
418		defer timer.Stop()
419		select {
420		case <-ctx.Done():
421			return false
422		case <-timer.C:
423			return true
424		}
425	}
426	
427	// tcpAlivenessProber tests endpoint reachability via a TCP connect probe.
428	func tcpAlivenessProber(ctx context.Context, _, baseURL string) bool {
429		addr := extractHostPort(baseURL)
430		if addr == "" {
431			return false
432		}
433		d := net.Dialer{}
434		conn, err := d.DialContext(ctx, "tcp", addr)
435		if err != nil {
436			return false
437		}
438		_ = conn.Close()
439		return true
440	}
441	
442	// extractHostPort extracts host:port from a base URL, adding the scheme's
443	// default port when none is specified.
444	func extractHostPort(baseURL string) string {
445		baseURL = strings.TrimSpace(baseURL)
446		if baseURL == "" {
447			return ""
448		}
449		if !strings.Contains(baseURL, "://") {
450			baseURL = "http://" + baseURL
451		}
452		u, err := url.Parse(baseURL)
453		if err != nil {
454			return ""
455		}
456		host := u.Host
457		if host == "" {
458			return ""
459		}
460		if !strings.Contains(host, ":") {
461			switch u.Scheme {
462			case "https":
463				host += ":443"
464			default:
465				host += ":80"
466			}
467		}
468		return host
469	}
