63	// HasModel returns true when the exact model pin is within the static
64	// harness allow-list. A nil allow-list means the harness delegates validation
65	// to provider-side model checks.
66	func (c Capabilities) HasModel(model string) bool {
67		if c.SupportedModels == nil || model == "" {
68			return true
69		}
70		for _, supported := range c.SupportedModels {
71			if supported == model {
72				return true
73			}
74		}
75		return false
76	}
