78	// CheckGating applies all capability gates against a request and returns
79	// the first failure reason (free-form string for diagnostics) plus the
80	// typed FilterReason category for the failure. Returns ("", FilterReasonEligible)
81	// when all gates pass.
82	//
83	// The typed return is the authoritative classification — callers must not
84	// re-classify by parsing the string. The string is for human-readable
85	// diagnostics only.
86	//
87	// Fixes ddx-4817edfd subtree: pre-dispatch capability check covering
88	// context window, tool support, effort, permissions.
89	func CheckGating(cap Capabilities, req Request) (string, FilterReason) {
90		// Context window gating: if the request declares prompt size or an effort
91		// that implies a minimum context, reject candidates that can't fit.
92		minCtx := req.MinContextWindow()
93		if minCtx > 0 {
94			if cap.ContextWindow <= 0 {
95				return fmt.Sprintf("context window unknown < required %d", minCtx), FilterReasonContextTooSmall
96			}
97			if cap.ContextWindow < minCtx {
98				return fmt.Sprintf("context window %d < required %d", cap.ContextWindow, minCtx), FilterReasonContextTooSmall
99			}
100		}
101	
102		// Tool-calling support gating.
103		if req.RequiresTools && !cap.SupportsTools {
104			return "tool calling not supported", FilterReasonNoToolSupport
105		}
106	
107		if !cap.HasReasoning(req.Reasoning) {
108			return fmt.Sprintf("reasoning %q not supported", req.Reasoning), FilterReasonReasoningUnsupported
109		}
110	
111		// Permissions support gating.
112		if !cap.HasPermissions(req.Permissions) {
113			return fmt.Sprintf("permissions %q not supported", req.Permissions), FilterReasonScoredBelowTop
114		}
115	
116		if req.Model != "" && !cap.HasModel(req.Model) {
117			return "model not in harness allow-list", FilterReasonScoredBelowTop
118		}
119	
120		// Exact-pin gating: an explicit Model field requires ExactPinSupport.
121		if req.Model != "" && !cap.ExactPinSupport {
122			return "exact model pin not supported", FilterReasonScoredBelowTop
123		}
124	
125		return "", FilterReasonEligible
126	}
127	
128	// CheckPowerEligibility applies catalog-power gates for automatic model
129	// selection. Explicit Model and Provider pins bypass this gate so caller-
130	// chosen routes are never broadened or overridden by power policy. A Harness
131	// pin with an empty Model still flows through this gate because the engine is
132	// choosing within that harness's eligible model set.
133	func CheckPowerEligibility(lookup func(string) (ModelEligibility, bool), model string, req Request) (string, FilterReason) {
134		if req.Model != "" || req.Provider != "" || lookup == nil {
135			return "", FilterReasonEligible
136		}
137		if model == "" {
138			return "model has no catalog power metadata", FilterReasonPowerMissing
139		}
140		eligibility, ok := lookup(model)
141		if !ok {
142			if req.MinPower > 0 || req.MaxPower > 0 {
143				return fmt.Sprintf("model %q has no catalog power metadata", model), FilterReasonPowerMissing
144			}
145			return "", FilterReasonEligible
146		}
147		if eligibility.ExactPinOnly {
148			return fmt.Sprintf("model %q is exact-pin-only", model), FilterReasonExactPinOnly
149		}
150		if !eligibility.AutoRoutable {
151			if eligibility.Power <= 0 {
152				return fmt.Sprintf("model %q has no catalog power metadata", model), FilterReasonPowerMissing
153			}
154			return fmt.Sprintf("model %q is not auto-routable", model), FilterReasonNotAutoRoutable
155		}
156		return "", FilterReasonEligible
157	}
158	
159	// CheckProviderDefaultEligibility returns a rejection reason when the provider
160	// entry has ExcludeFromDefaultRouting=true and the request does not carry an
161	// explicit provider, harness, or exact model pin. Any explicit hard pin
162	// bypasses this gate so the operator can still reach opt-out providers
163	// intentionally.
164	func CheckProviderDefaultEligibility(providerName string, actualCashSpend bool, billing modelcatalog.BillingModel, excluded bool, req Request) (string, FilterReason) {
165		if !excluded {
166			return "", FilterReasonEligible
167		}
168		if req.Provider != "" || req.Harness != "" || req.Model != "" {
169			return "", FilterReasonEligible
170		}
171		if actualCashSpend || billing == modelcatalog.BillingModelPerToken {
172			return fmt.Sprintf("pay-per-token provider %s requires metered opt-in for unpinned automatic routing", providerName), FilterReasonMeteredOptInRequired
173		}
174		return fmt.Sprintf("provider %s excluded from default routing (include_by_default=false)", providerName), FilterReasonProviderExcludedFromDefault
175	}
176	
177	// resolveRequestReasoning returns a copy of req with Reasoning resolved to the
178	// catalog's reasoning default for the request's policy/surface
179	// when the request asks for Reasoning=auto. This must run before CheckGating
180	// so candidates that only support a different reasoning level (e.g. an
181	// off-only variant under a policy whose surface default is "high") are
182	// correctly disqualified by the capability gate. Other Reasoning values
183	// (unset, off, named, numeric) are left untouched, preserving the existing
184	// behavior of those code paths.
185	func resolveRequestReasoning(req Request, surface string, resolver func(policy, surface string) (string, bool)) Request {
186		if resolver == nil || req.Policy == "" {
187			return req
188		}
189		policy, err := reasoning.ParseString(req.Reasoning)
190		if err != nil || policy.Kind != reasoning.KindAuto {
191			return req
192		}
193		resolved, ok := resolver(req.Policy, surface)
194		if !ok || resolved == "" {
195			return req
196		}
197		out := req
198		out.Reasoning = resolved
199		return out
200	}
